411	     1	/**
412	     2	 * Generic fuzzy-match of an input name against any array of records.
413	     3	 * nameField: the record property to match against (default 'licensor_name').
414	     4	 * Returns the matched record or null if no reasonable match found.
415	     5	 */
416	     6	function fuzzyMatch(inputName, records, nameField = 'licensor_name') {
417	     7	  if (!records || !records.length || !inputName) return null;
418	     8	  const input = (inputName || '').toLowerCase().trim();
419	     9	  const getName = r => (r[nameField] || '').toLowerCase().trim();
420	    10	
421	    11	  // 1. Exact match
422	    12	  let match = records.find(r => getName(r) === input);
423	    13	  if (match) return match;
424	    14	
425	    15	  // 2. Input contains the record name or vice versa
426	    16	  match = records.find(r => {
427	    17	    const name = getName(r);
428	    18	    return input.includes(name) || name.includes(input);
429	    19	  });
430	    20	  if (match) return match;
431	    21	
432	    22	  // 3. Word overlap scoring
433	    23	  const inputWords = input.split(/[\s\-\/\(\),]+/).filter(w => w.length > 2);
434	    24	  let bestScore = 0;
435	    25	  let bestMatch = null;
436	    26	  for (const r of records) {
437	    27	    const nameWords = getName(r).split(/[\s\-\/\(\),]+/).filter(w => w.length > 2);
438	    28	    let score = 0;
439	    29	    for (const word of inputWords) {
440	    30	      if (nameWords.some(nw => nw.includes(word) || word.includes(nw))) score++;
441	    31	    }
442	    32	    if (score > bestScore) {
443	    33	      bestScore = score;
444	    34	      bestMatch = r;
445	    35	    }
446	    36	  }
447	    37	  if (bestMatch && bestScore > 0) return bestMatch;
448	    38	
449	    39	  return null;
450	    40	}
451	    41	
