    42	// Helper: fuzzy match a name against a list of records, return best match or first record as fallback
    43	function fuzzyMatch(inputName, records, nameField) {
    44	  if (!records || records.length === 0) return null;
    45	  const input = (inputName || '').toLowerCase().trim();
    46	
    47	  // 1. Exact match
    48	  let match = records.find(r => (r[nameField] || '').toLowerCase().trim() === input);
    49	  if (match) return { record: match, matchType: 'exact' };
    50	
    51	  // 2. Input contains the template name or vice versa
    52	  match = records.find(r => {
    53	    const templateName = (r[nameField] || '').toLowerCase().trim();
    54	    return input.includes(templateName) || templateName.includes(input);
    55	  });
    56	  if (match) return { record: match, matchType: 'partial' };
    57	
    58	  // 3. Word overlap matching — score by number of shared words
    59	  const inputWords = input.split(/[\s\-\/\(\),]+/).filter(w => w.length > 2);
    60	  let bestScore = 0;
    61	  let bestMatch = null;
    62	  for (const r of records) {
    63	    const templateWords = (r[nameField] || '').toLowerCase().split(/[\s\-\/\(\),]+/).filter(w => w.length > 2);
    64	    let score = 0;
    65	    for (const word of inputWords) {
    66	      if (templateWords.some(tw => tw.includes(word) || word.includes(tw))) {
    67	        score++;
    68	      }
    69	    }
    70	    if (score > bestScore) {
    71	      bestScore = score;
    72	      bestMatch = r;
    73	    }
    74	  }
    75	  if (bestMatch && bestScore > 0) return { record: bestMatch, matchType: 'word-overlap' };
    76	
    77	  // 4. Fallback: return first record
    78	  return { record: records[0], matchType: 'default' };
    79	}
