 34	 * Map ag-Grid-style filterModel to Sequelize where fragments for ProdOrderHeader scalar columns.
 35	 * Only text filters on DB column ids are applied (same idea as getProdOrderHeader query params).
 36	 */
 37	function buildFactoryProdOrderFilterWhere(filterModel) {
 38	  if (!filterModel || typeof filterModel !== 'object') {
 39	    return null;
 40	  }
 41	  const clauses = [];
 42	  for (const [colId, def] of Object.entries(filterModel)) {
 43	    if (!def) {
 44	      continue;
 45	    }
 46	    const isText =
 47	      def.filterType === 'text' ||
 48	      def.filterType === 'agTextColumnFilter';
 49	    if (!isText) {
 50	      continue;
 51	    }
 52	    const val = typeof def.filter === 'string' ? def.filter.trim() : '';
 53	    if (!val) {
 54	      continue;
 55	    }
 56	    if (['prodReferenceNo', 'prodOrderNo', 'vendorCode'].includes(colId)) {
 57	      clauses.push({ [colId]: { [Op.iLike]: `%${val}%` } });
 58	    }
 59	  }
 60	  if (!clauses.length) {
 61	    return null;
 62	  }
 63	  return clauses.length === 1 ? clauses[0] : { [Op.and]: clauses };
 64	}
