 66	async function getVendorCodesForFactoryId(factoryId) {
 67	  if (factoryId === undefined || factoryId === null || factoryId === '') {
 68	    return null;
 69	  }
 70	  const id = Number(factoryId);
 71	  if (Number.isNaN(id)) {
 72	    return null;
 73	  }
 74	
 75	  const runJoin = async (vendorTable, extVendorTable) => {
 76	    return sql.sequelize.query(
 77	      `SELECT DISTINCT ev."vendorCode" AS "vendorCode"
 78	       FROM ${extVendorTable} ev
 79	       INNER JOIN ${vendorTable} v
 80	         ON lower(trim(COALESCE(v."vendor_email", ''))) = lower(trim(COALESCE(ev.email, '')))
 81	       WHERE v."factory_id_fk" = :factoryId
 82	         AND ev."vendorCode" IS NOT NULL`,
 83	      { replacements: { factoryId: id }, type: Sequelize.QueryTypes.SELECT }
 84	    );
 85	  };
 86	
 87	  /** Same as an IN-subquery — sometimes more reliable across search_path than a raw join naming. */
 88	  const runInSubquery = async (vendorTable, extVendorTable) => {
 89	    return sql.sequelize.query(
 90	      `SELECT DISTINCT ev."vendorCode" AS "vendorCode"
 91	       FROM ${extVendorTable} ev
 92	       WHERE ev."vendorCode" IS NOT NULL
 93	         AND lower(trim(COALESCE(ev.email, ''))) IN (
 94	           SELECT lower(trim(COALESCE(v2."vendor_email", '')))
 95	           FROM ${vendorTable} v2
 96	           WHERE v2."factory_id_fk" = :factoryId
 97	             AND v2."vendor_email" IS NOT NULL
 98	             AND trim(COALESCE(v2."vendor_email", '')) <> ''
 99	         )`,
100	      { replacements: { factoryId: id }, type: Sequelize.QueryTypes.SELECT }
101	    );
102	  };
103	
104	  const qualifiedPairs = [
105	    [qualifyTableName('vendor'), qualifyTableName('externalVendor')],
106	    ['"vendor"', '"externalVendor"']
107	  ];
108	
109	  let rows = [];
110	  for (const [vt, et] of qualifiedPairs) {
111	    try {
112	      rows = await runJoin(vt, et);
113	      if (rows.length) {
114	        break;
115	      }
116	      rows = await runInSubquery(vt, et);
117	      if (rows.length) {
118	        break;
119	      }
120	    } catch (e) {
121	      rows = [];
122	    }
123	  }
124	
125	  let codes = rows.map((r) => r.vendorCode).filter(Boolean);
126	  if (codes.length) {
127	    return codes;
128	  }
129	
130	  for (const vt of [qualifyTableName('vendor'), '"vendor"']) {
131	    try {
132	      const emailRows = await sql.sequelize.query(
133	        `SELECT DISTINCT lower(trim(COALESCE("vendor_email", ''))) AS em
134	         FROM ${vt}
135	         WHERE "factory_id_fk" = :factoryId
136	           AND trim(COALESCE("vendor_email", '')) <> ''`,
137	        { replacements: { factoryId: id }, type: Sequelize.QueryTypes.SELECT }
138	      );
139	      const emails = emailRows.map((r) => r.em).filter(Boolean);
140	      if (!emails.length) {
141	        continue;
142	      }
143	      const evs = await sql.externalVendor.findAll({
144	        attributes: ['vendorCode'],
145	        where: {
146	          [Op.or]: emails.map((em) =>
147	            sql.sequelize.where(
148	              sql.sequelize.fn('lower', sql.sequelize.col('email')),
149	              em
150	            )
151	          )
152	        }
153	      });
154	      codes = [...new Set(evs.map((e) => e.vendorCode).filter(Boolean))];
155	      if (codes.length) {
156	        return codes;
157	      }
158	    } catch (e) {
159	      /* try next table qualification */
160	    }
161	  }
162	
163	  return [];
164	}
