520	ProdTracking.syncPrepackAssociations = async (req, result) => {
521	  try {
522	    // Step 1: Get all ProdOrderDetails with a non-null/empty prepackCode
523	    const details = await sql.ProdOrderDetail.findAll({
524	      where: { prepackCode: { [Op.not]: null, [Op.ne]: '' } },
525	      attributes: ['pkey', 'prepackCode']
526	    });
527	
528	    // Step 2: Group pkeys by prepackCode to avoid redundant API calls
529	    const byPrepack = {};
530	    for (const d of details) {
531	      const code = d.dataValues.prepackCode;
532	      if (!byPrepack[code]) byPrepack[code] = [];
533	      byPrepack[code].push(d.dataValues.pkey);
534	    }
535	
536	    let totalUpserted = 0;
537	    for (const [prepackCode, pkeys] of Object.entries(byPrepack)) {
538	      let subItems;
539	      try {
540	        // Step 3: Call ColdLion prepackDetail API
541	        const { data } = await axios.get(
542	          'http://x5.coldlion.com/EhpApi/prepackDetail',
543	          {
544	            params: { companyCode: 'EDGEHOME', prepackCode },
545	            headers: { 'X-API-Key': 'Z21355JALT13A54L9X5' }
546	          }
547	        );
548	        subItems = data;
549	      } catch (apiErr) {
550	        console.error(`prepackDetail API failed for prepackCode=${prepackCode}:`, apiErr.message);
551	        continue;
552	      }
553	
554	      if (!Array.isArray(subItems) || !subItems.length) continue;
555	
556	      for (const subItem of subItems) {
557	        // Step 4: Find matching itemHeader by item_num_id = subItem.itemNo
558	        const header = await sql.itemHeader.findOne({
559	          where: { item_num_id: subItem.itemNo },
560	          attributes: ['item_id_pk']
561	        });
562	        if (!header) {
563	          console.warn(`No itemHeader found for itemNo=${subItem.itemNo}`);
564	          continue;
565	        }
566	
567	        // Step 5: Upsert one association row per (ProdOrderDetail, itemHeader) pair
568	        for (const pkey of pkeys) {
569	          await sql.item_prod_order_detail_associations.upsert({
570	            itemHeaderId: header.item_id_pk,
571	            prodOrderDetailPkey: pkey,
572	            matchedItemNumber: subItem.itemNo,
573	            masterQuantity: subItem.quantity,
574	            matchSource: 'prepack_code'
575	          });
576	          totalUpserted++;
577	        }
578	      }
579	    }
580	
581	    result(null, { success: true, totalUpserted });
582	  } catch (err) {
583	    console.error('Error in syncPrepackAssociations:', err);
584	    result(err, null);
585	  }
586	};
