 19	LicTracking.getAllLicenses = async (req, result) => {
 20	  const { startRow, endRow, filterModel } = req.query;
 21	  const limit = endRow - startRow;
 22	  const offset = Number(startRow);
 23	
 24	  try {
 25	    const filters = filterModel ? JSON.parse(filterModel) : {};
 26	
 27	    // 🔹 Normalize multi filters (same as ItemLibrary)
 28	    Object.keys(filters).forEach(field => {
 29	      if (filters[field]?.filterType === 'multi') {
 30	        const validSubFilter = filters[field].filterModels.find(sub => sub);
 31	        filters[field] = validSubFilter || null;
 32	      }
 33	    });
 34	
 35	    const whereClause = {};
 36	
 37	    if (req.query.companyCode) {
 38	      whereClause.compan_code_fk = Number(req.query.companyCode);
 39	    }
 40	
 41	    // 🔹 SAME merchGroupFilters structure
 42	    const merchGroupFilters = {
 43	      merchGroup01: {},
 44	      merchGroup02: {},
 45	      merchGroup03: {},
 46	      merchGroup04: {},
 47	      merchGroup05: {},
 48	      merchGroup06: {}
 49	    };
 50	
 51	    // 🔹 SAME buildCondition (no db logic)
 52	    const buildCondition = (filterDef) => {
 53	      if (filterDef.filterType === 'date') {
 54	        const { type, dateFrom, dateTo } = filterDef;
 55	        if (!dateFrom) return null;
 56	
 57	        const startOfDay = new Date(dateFrom);
 58	        startOfDay.setHours(0, 0, 0, 0);
 59	
 60	        const endOfDay = new Date(startOfDay);
 61	        endOfDay.setHours(23, 59, 59, 999);
 62	
 63	        switch (type) {
 64	          case 'equals': return { [Op.between]: [startOfDay, endOfDay] };
 65	          case 'notEqual': return { [Op.notBetween]: [startOfDay, endOfDay] };
 66	          case 'lessThan': return { [Op.lt]: startOfDay };
 67	          case 'greaterThan': return { [Op.gt]: startOfDay };
 68	          case 'inRange':
 69	            if (!dateTo) return null;
 70	            const rangeEnd = new Date(dateTo);
 71	            rangeEnd.setHours(23, 59, 59, 999);
 72	            return { [Op.between]: [startOfDay, rangeEnd] };
 73	          default: return null;
 74	        }
 75	      }
 76	
 77	      
 78	      if(filterDef.filterType === 'text'){
 79	        const value =
 80	        typeof filterDef.filter === 'string' ? filterDef.filter : '';
 81	
 82	      switch (filterDef.type) {
 83	        case 'contains': return { [Op.iLike]: `%${value}%` };
 84	        case 'notContains': return { [Op.notILike]: `%${value}%` };
 85	        case 'equals': return { [Op.eq]: filterDef.filter };
 86	        case 'notEqual': return { [Op.ne]: filterDef.filter };
 87	        case 'startsWith': return { [Op.iLike]: `${value}%` };
 88	        case 'endsWith': return { [Op.iLike]: `%${value}` };
 89	        case 'blank': return { [Op.or]: [{ [Op.eq]: null }, { [Op.eq]: '' }] };
 90	        case 'notBlank': return { [Op.and]: [{ [Op.ne]: null }, { [Op.ne]: '' }] };
 91	        default: return null;
 92	      }
 93	      }
 94	
 95	    };
 96	
 97	    // 🔹 SAME filter routing logic
 98	    Object.entries(filters).forEach(([field, filterDef]) => {
 99	      if (!filterDef) return;
100	
101	      const dbField = mapFieldToColumn(field);
102	      const condition = buildCondition(filterDef);
103	      if (!condition) return;
104	
105	      // ✅ EXACT SAME REGEX AS ItemLibrary
106	      const match = dbField.match(/^merchGroup0([1-6])/);
107	      if (match) {
108	        const key = `merchGroup0${match[1]}`;
109	        merchGroupFilters[key] = condition;
110	      } else {
111	        whereClause[dbField] = condition;
112	      }
113	    });
114	
115	    // 🔹 Division codes (same pattern)
116	    const andConditions = [];
117	    const divisionCodeIds = req.query.divisionCodeIds
118	      ? JSON.parse(req.query.divisionCodeIds)
119	      : [];
120	
121	    if (divisionCodeIds.length > 0) {
122	      (divisionCodeIds.includes(1)) ? divisionCodeIds.push(2) : null;
123	      andConditions.push({
124	        [Op.or]: [
125	          { div_code_fk: { [Op.in]: divisionCodeIds } },
126	          { div_code_fk: null }
127	        ]
128	      });
129	    }
130	
131	    if (andConditions.length > 0) {
132	      whereClause[Op.and] = andConditions;
133	    }
134	
135	    // 🔹 SAME merchGroup include generator
136	    const generateMerchGroupIncludes = () =>
137	      Object.entries(merchGroupFilters).map(([key, filter]) => {
138	        const match = key.match(/^merchGroup0([1-6])/);
139	        const hasFilter = Reflect.ownKeys(filter).length > 0;
140	
141	        return {
142	          model: sql.merchGroup,
143	          as: key,
144	          required: hasFilter,
145	          where: hasFilter
146	            ? {
147	                mgTypeCode: `0${match[1]}`,
148	                mg_desc: filter
149	              }
150	            : undefined
151	        };
152	      });
153	
154	    const merchIncludes = generateMerchGroupIncludes();
155	
156	    // 🔹 Single query for both count and data
157	    const { count, rows } = await sql.itemHeader.findAndCountAll({
158	      where: whereClause,
159	      logging: console.log,
160	      order: [['item_id_pk', 'DESC']],
161	      limit,
162	      offset,
163	      distinct: true,
164	      include: [
165	        { model: sql.externalVendor, as: 'externalVendor' },
166	        { model: sql.itemAttachment, as: 'itemAttachments' },
167	        { model: sql.itemLicenseImage, as: 'licenseImages', required: false },
168	        { model: sql.comments, as: 'comments', required: false },
169	        {
170	          model: sql.licensingStatus,
171	          as: 'licensingStatuses',
172	          required: !!(filters?.license_status?.values?.length),
173	          where: {
174	            ...(filters?.license_status?.values?.length ? {
175	              status: { [Op.in]: filters.license_status.values }
176	            } : {}),
177	            id: { [Op.eq]: Sequelize.literal(`(
178	              SELECT MAX(id) 
179	              FROM "${process.env.SCHEMA}"."licensingStatus" AS "ls" 
180	              WHERE CAST("ls"."itemheader_id_fk" AS INTEGER) = "itemHeader"."item_id_pk"
181	            )`) }
182	          }
183	        },
184	        ...merchIncludes
185	      ]
186	    });
187	
188	    const colHeaders = await getGridHeader(['licensing_tracking']);
189	    const licensorGroups = await sql.merchGroup.findAll({
190	      where: {
191	        mgTypeCode: '05',
192	        divisionCode_id_fk: { [Op.in]: [1, 8] }
193	      }
194	    });
195	
196	    const remappedData = await utility.remapLicItem(
197	      colHeaders,
198	      rows,
199	      licensorGroups
200	    );
201	
202	    result(null, {
203	      rows: remappedData,
204	      totalCount: count
205	    });
206	  } catch (err) {
207	    console.error('Error in getAllLicenses:', err);
208	    result(null, err);
209	  }
